-- Idriss Auto — bulk car parts seed (630 rows)
-- Run in Supabase -> SQL Editor -> New query -> paste -> Run.
-- Safe to re-run (upserts by id). These are common maintenance/wear parts
-- mapped to popular vehicles; OEM part numbers are intentionally left blank —
-- fill exact numbers later from a verified catalog before professional use.
-- Idea & developed by Idriss Romdhani.

on conflict (id) do update
  set category = excluded.category,
      name     = excluded.name,
      fits     = excluded.fits;
